-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0001_extensions_and_helpers.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0001 — EXTENSIONS & GENERIC HELPERS
-- =========================================================
create extension if not exists pgcrypto;   -- gen_random_uuid()
create extension if not exists pg_trgm;    -- fast ILIKE / fuzzy search on text (search feature, Phase 5)

-- Generic trigger: keeps updated_at current on every UPDATE.
-- Applied to every table below that has an updated_at column.
create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0002_roles_permissions.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0002 — ROLES & PERMISSIONS (normalized RBAC)
-- Seed data here is structural (role/permission definitions), not content.
-- =========================================================
create table roles (
  id uuid primary key default gen_random_uuid(),
  key text not null unique,              -- 'super_admin' | 'admin' | 'editor' | 'user'
  name text not null,
  description text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create trigger trg_roles_updated_at before update on roles
  for each row execute function public.set_updated_at();

create table permissions (
  id uuid primary key default gen_random_uuid(),
  key text not null unique,              -- e.g. 'posts.manage'
  description text,
  created_at timestamptz not null default now()
);

create table role_permissions (
  role_id uuid not null references roles(id) on delete cascade,
  permission_id uuid not null references permissions(id) on delete cascade,
  primary key (role_id, permission_id)
);
create index idx_role_permissions_permission on role_permissions(permission_id);

-- ---------- Seed: base roles ----------
insert into roles (key, name, description) values
