-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0003_profiles.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0003 — PROFILES (1:1 extension of auth.users)
-- Replaces the old "admin_profiles" table with a unified profile
-- for every authenticated user (admins today, public users in Phase 2+).
-- =========================================================
create table profiles (
  id uuid primary key references auth.users(id) on delete cascade,
  role_id uuid not null references roles(id),
  full_name text,
  avatar_url text,
  is_active boolean not null default true,
  last_login_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create index idx_profiles_role_id on profiles(role_id);

create trigger trg_profiles_updated_at before update on profiles
  for each row execute function public.set_updated_at();

-- Auto-create a base "user" profile whenever a new Supabase auth account is
-- created. Admin roles are never self-assigned — an existing super_admin
-- must promote the account afterwards (see README / DB docs).
create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into public.profiles (id, role_id, full_name)
  values (
    new.id,
    (select id from public.roles where key = 'user'),
    new.raw_user_meta_data ->> 'full_name'
  );
  return new;
end;
$$;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0004_rbac_functions_and_core_rls.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0004 — RBAC HELPER FUNCTIONS + RLS FOR ROLES/PERMISSIONS/PROFILES
-- =========================================================

-- Returns true if the currently authenticated user's role has the given
-- permission key. Used in every RLS policy below instead of repeating
-- role-lookup joins everywhere.
create or replace function public.has_permission(perm_key text)
returns boolean
language sql
stable
as $$
  select exists (
    select 1
    from profiles p
    join role_permissions rp on rp.role_id = p.role_id
    join permissions perm on perm.id = rp.permission_id
    where p.id = auth.uid()
      and p.is_active = true
      and perm.key = perm_key
  );
$$;

-- Returns true if the user has ANY admin-level permission at all — used to
-- gate "can this account even open /admin" checks (middleware, layout).
create or replace function public.is_admin_user()
returns boolean
language sql
stable
as $$
  select exists (
    select 1
    from profiles p
    join role_permissions rp on rp.role_id = p.role_id
    where p.id = auth.uid()
      and p.is_active = true
  );
$$;

-- ---------- RLS: roles / permissions / role_permissions ----------
-- NOTE: the SELECT policies below are superseded by migration 0020
-- (tightened from "any authenticated user" to "admin accounts only").
-- Kept here unmodified so migration history stays accurate/replayable.
alter table roles enable row level security;
alter table permissions enable row level security;
alter table role_permissions enable row level security;

create policy "authenticated read roles" on roles
  for select using (auth.role() = 'authenticated');
create policy "roles.manage write roles" on roles
  for all using (has_permission('roles.manage')) with check (has_permission('roles.manage'));

create policy "authenticated read permissions" on permissions
  for select using (auth.role() = 'authenticated');
create policy "roles.manage write permissions" on permissions
  for all using (has_permission('roles.manage')) with check (has_permission('roles.manage'));

create policy "authenticated read role_permissions" on role_permissions
  for select using (auth.role() = 'authenticated');
create policy "roles.manage write role_permissions" on role_permissions
  for all using (has_permission('roles.manage')) with check (has_permission('roles.manage'));

-- ---------- RLS: profiles ----------
alter table profiles enable row level security;

-- Everyone can read + update their own profile row.
create policy "self read profile" on profiles
  for select using (id = auth.uid());
create policy "self update profile" on profiles
  for update using (id = auth.uid())
  with check (id = auth.uid());

-- Guard against self-elevation: if the person making the change does NOT
-- hold users.manage, silently keep their role_id unchanged no matter what
-- value they submitted. (A trigger is used instead of an RLS check because
-- RLS CHECK clauses cannot reliably compare NEW vs OLD on the same row.)
create or replace function public.prevent_self_role_escalation()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  if new.id = auth.uid() and not has_permission('users.manage') then
    new.role_id := old.role_id;
  end if;
  return new;
end;
$$;

create trigger trg_prevent_self_role_escalation
  before update on profiles
  for each row execute function public.prevent_self_role_escalation();

-- users.manage holders can read & update anyone's profile (e.g. to change roles).
create policy "users.manage read all profiles" on profiles
  for select using (has_permission('users.manage'));
create policy "users.manage update all profiles" on profiles
  for update using (has_permission('users.manage'))
  with check (has_permission('users.manage'));

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0005_audit_logs.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0005 — AUDIT LOGS
-- Automatic, tamper-resistant change history for every sensitive table.
-- Rows are written by a SECURITY DEFINER trigger, never by the app
-- directly — no role (not even admins) gets INSERT/UPDATE/DELETE on
-- this table, only logs.view holders may read it.
-- =========================================================
create table audit_logs (
  id uuid primary key default gen_random_uuid(),
  actor_id uuid references profiles(id) on delete set null,
  action text not null check (action in ('INSERT', 'UPDATE', 'DELETE')),
  table_name text not null,
  record_id uuid,
  old_data jsonb,
  new_data jsonb,
  created_at timestamptz not null default now()
);

-- BRIN index: ideal for large, append-only, time-ordered tables (millions
-- of rows) — far smaller and faster to maintain here than a btree.
create index idx_audit_logs_created_at_brin on audit_logs using brin (created_at);
create index idx_audit_logs_table_record on audit_logs (table_name, record_id);
create index idx_audit_logs_actor on audit_logs (actor_id);

create or replace function public.audit_trigger()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  if (tg_op = 'DELETE') then
    insert into audit_logs (actor_id, action, table_name, record_id, old_data)
    values (auth.uid(), 'DELETE', tg_table_name, old.id, to_jsonb(old));
    return old;
  elsif (tg_op = 'UPDATE') then
    insert into audit_logs (actor_id, action, table_name, record_id, old_data, new_data)
    values (auth.uid(), 'UPDATE', tg_table_name, new.id, to_jsonb(old), to_jsonb(new));
    return new;
  elsif (tg_op = 'INSERT') then
    insert into audit_logs (actor_id, action, table_name, record_id, new_data)
    values (auth.uid(), 'INSERT', tg_table_name, new.id, to_jsonb(new));
    return new;
  end if;
  return null;
end;
$$;

alter table audit_logs enable row level security;
create policy "logs.view read audit_logs" on audit_logs
  for select using (has_permission('logs.view'));
-- Intentionally no insert/update/delete policy for any role: only the
-- SECURITY DEFINER trigger function can write here.

