create policy "apk.manage update apk bucket" on storage.objects
  for update using (bucket_id = 'apk' and has_permission('apk.manage'));
create policy "apk.manage delete apk bucket" on storage.objects
  for delete using (bucket_id = 'apk' and has_permission('apk.manage'));

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0020_phase1_hardening.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0020 — PHASE 1 VERIFICATION FIXES
-- Found during the Phase 1 verification pass (see DATABASE_TEST_REPORT.md
-- and SECURITY_REPORT.md). Applied as a new migration rather than editing
-- migration history, per standard practice.
-- =========================================================

-- ---------------------------------------------------------------
-- FIX 1 — audit_trigger() requires a NEW/OLD.id column. profiles, roles
-- and permissions all have one, but were missing the trigger entirely —
-- meaning role changes and permission-catalogue edits were NOT being
-- logged. These are the most security-sensitive tables in the whole
-- schema, so this was a real gap.
-- ---------------------------------------------------------------
create trigger trg_audit_profiles
  after insert or update or delete on profiles
  for each row execute function public.audit_trigger();

create trigger trg_audit_roles
  after insert or update or delete on roles
  for each row execute function public.audit_trigger();

create trigger trg_audit_permissions
  after insert or update or delete on permissions
  for each row execute function public.audit_trigger();

-- ---------------------------------------------------------------
-- FIX 2 — role_permissions has a composite primary key (role_id,
-- permission_id), not an `id` column, so the generic audit_trigger()
-- would fail at runtime ("record new has no field id") if attached
-- directly. A dedicated composite-key variant is used instead so that
-- privilege-grant changes (e.g. removing roles.manage from admin) are
-- still fully audited.
-- ---------------------------------------------------------------
create or replace function public.audit_trigger_composite_key()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  if (tg_op = 'DELETE') then
    insert into audit_logs (actor_id, action, table_name, old_data)
    values (auth.uid(), 'DELETE', tg_table_name, to_jsonb(old));
    return old;
  elsif (tg_op = 'INSERT') then
    insert into audit_logs (actor_id, action, table_name, new_data)
    values (auth.uid(), 'INSERT', tg_table_name, to_jsonb(new));
    return new;
  end if;
  return null;
end;
$$;

create trigger trg_audit_role_permissions
  after insert or delete on role_permissions
  for each row execute function public.audit_trigger_composite_key();

-- ---------------------------------------------------------------
-- FIX 3 — roles / permissions / role_permissions were readable by ANY
-- authenticated account (auth.role() = 'authenticated'). Phase 2 will
-- introduce plain public "user" accounts, which should NOT be able to
-- read the internal permission/role structure. Tightened to
-- is_admin_user() (true only for accounts whose role actually grants at
-- least one admin permission).
-- ---------------------------------------------------------------
drop policy "authenticated read roles" on roles;
create policy "admins read roles" on roles
  for select using (is_admin_user());

drop policy "authenticated read permissions" on permissions;
create policy "admins read permissions" on permissions
  for select using (is_admin_user());

drop policy "authenticated read role_permissions" on role_permissions;
create policy "admins read role_permissions" on role_permissions
  for select using (is_admin_user());

-- ---------------------------------------------------------------
-- FIX 4 — post_tags was readable by literally anyone with no check that
-- the associated post is actually published. This let an outside caller
-- discover tag associations (post_id + tag_id pairs) for DRAFT/unpublished
-- posts by querying the table directly, bypassing the posts table's own
-- "published only" public policy (low-severity info leak, but a real gap).
-- ---------------------------------------------------------------
drop policy "public read post_tags" on post_tags;
create policy "public read post_tags of published posts" on post_tags
  for select using (
    exists (
      select 1 from posts p
      where p.id = post_tags.post_id
        and p.status = 'published'
        and p.deleted_at is null
    )
  );

-- ---------------------------------------------------------------
-- FIX 5 — support_conversations / support_messages allowed an anonymous
-- visitor to INSERT with check(true), meaning anyone could set
-- status = 'resolved', assign an arbitrary assigned_admin_id, or — most
-- seriously — insert a message with sender = 'admin' into ANY conversation
-- id, spoofing a fake admin reply. Insert policies are now scoped to only
-- the fields a real visitor should be able to set.
-- ---------------------------------------------------------------
drop policy "anon insert conversation" on support_conversations;
create policy "anon insert open conversation" on support_conversations
  for insert with check (status = 'open' and assigned_admin_id is null);

drop policy "anon insert message" on support_messages;
create policy "anon insert visitor message" on support_messages
  for insert with check (sender = 'visitor');

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0021_phase2_roles_expansion.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0021 — PHASE 2: EXPAND ROLES TO FULL 8-ROLE MATRIX
-- Adds: moderator, support, affiliate_manager, content_manager
-- (super_admin, admin, editor, user already exist from 0002).
-- =========================================================
insert into roles (key, name, description) values
  ('moderator',         'Moderator',         'Moderates match insights, FAQs and support conversations'),
  ('support',           'Support',           'Handles support conversations only'),
  ('affiliate_manager', 'Affiliate Manager', 'Manages promotions, advertisements and APK releases'),
  ('content_manager',   'Content Manager',   'Senior content role: posts, football news, match insights, media, taxonomy, FAQs, navigation');

-- content_manager: broader content oversight than editor (adds taxonomy, faqs, navigation)
insert into role_permissions (role_id, permission_id)
select (select id from roles where key = 'content_manager'), id
from permissions
where key in (
  'posts.manage', 'football_news.manage', 'match_insights.manage',
  'media.manage', 'taxonomy.manage', 'faqs.manage', 'navigation.manage'
);

-- moderator: content moderation + support triage
insert into role_permissions (role_id, permission_id)
select (select id from roles where key = 'moderator'), id
from permissions
where key in ('support.manage', 'match_insights.manage', 'faqs.manage');

-- support: support conversations only
insert into role_permissions (role_id, permission_id)
select (select id from roles where key = 'support'), id
from permissions
where key = 'support.manage';

-- affiliate_manager: monetization-adjacent modules
insert into role_permissions (role_id, permission_id)
select (select id from roles where key = 'affiliate_manager'), id
from permissions
where key in ('promotions.manage', 'advertisements.manage', 'apk.manage');

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0022_login_attempts.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0022 — LOGIN ATTEMPTS (brute-force protection / rate limiting)
-- Written exclusively by the server (service-role client) from the
-- /api/auth/login route — no RLS policy grants anon/authenticated
-- access at all, so this table is invisible to every normal client.
-- =========================================================
create table login_attempts (
  id uuid primary key default gen_random_uuid(),
  identifier text not null,     -- lowercased email being attempted
  ip_address text,
  user_agent text,
  success boolean not null,
  created_at timestamptz not null default now()
);
create index idx_login_attempts_identifier on login_attempts(identifier, created_at desc);
create index idx_login_attempts_ip on login_attempts(ip_address, created_at desc);
create index idx_login_attempts_created_at_brin on login_attempts using brin (created_at);

alter table login_attempts enable row level security;
-- Intentionally NO policies at all: only the service-role key (which
-- bypasses RLS entirely) may read/write this table.

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0023_profiles_locale.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0023 — PROFILE LOCALE (per-user UI language preference)
-- =========================================================
alter table profiles
  add column locale text not null default 'uz' check (locale in ('uz', 'ru', 'en'));

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0024_site_settings_phase3.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0024 — PHASE 3a: SITE SETTINGS EXPANSION + SECURE API CREDENTIALS
-- =========================================================

-- ---------- New site_settings keys (public, non-secret config) ----------
insert into site_settings (key, value) values
  ('footer', '{"description": "", "footer_text": ""}'),
  ('maintenance', '{"enabled": false, "message": ""}'),
  ('branding', '{"logo_media_id": null, "favicon_media_id": null}')
on conflict (key) do nothing;

-- Expand the existing "theme" row with the extra colour fields Phase 3
-- needs (site already has "theme" from 0014 with mode+accent_color).
update site_settings
set value = value || '{"secondary_color": "#FFC857", "background_color": "#07111F"}'::jsonb
where key = 'theme'
  and not (value ? 'secondary_color');

-- =========================================================
-- SECURE API CREDENTIALS
-- Stores secrets that must NEVER be exposed to the browser (football API
-- key, push notification server keys). Unlike site_settings, this table
-- has NO RLS policies at all for anon/authenticated — only the
-- service-role key (used exclusively from server-only API routes) can
-- read or write it. The admin UI never receives the actual secret value
-- back, only a "configured / not configured" status.
-- =========================================================
create table api_credentials (
  id uuid primary key default gen_random_uuid(),
  key text not null unique,   -- e.g. 'football_api_key', 'push_fcm_server_key'
  value text not null,
  is_active boolean not null default true,
  updated_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create trigger trg_api_credentials_updated_at before update on api_credentials
  for each row execute function public.set_updated_at();
create trigger trg_audit_api_credentials
  after insert or update or delete on api_credentials
  for each row execute function public.audit_trigger();

alter table api_credentials enable row level security;
-- Intentionally NO policies: only the service-role client can touch this
-- table, from server-only route handlers, after that route independently
-- verifies the caller holds settings.manage via has_permission().

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0025_affiliate_manager.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0025 — PHASE 3b: ENTERPRISE AFFILIATE MANAGER
-- Supersedes the simple Phase 1 "promotions" table (one row = one flat
-- promo code) with a proper Partner ↔ Promo Codes ↔ Redirect Rules ↔
-- Clicks model. Architecture supports unlimited affiliate companies —
-- nothing about any specific brand is hardcoded anywhere in this schema.
-- =========================================================

-- The old flat table is fully replaced by affiliate_partners + promo_codes
-- below; dropping it (cascade removes its indexes/triggers/policies) keeps
-- the schema free of two overlapping "promotion" concepts.
drop table if exists promotions cascade;

-- ---------------------------------------------------------------
-- AFFILIATE PARTNERS
-- ---------------------------------------------------------------
create table affiliate_partners (
  id uuid primary key default gen_random_uuid(),
  slug text not null unique,                  -- used in /go/{slug} redirect links
  name text not null check (char_length(name) between 1 and 200),
  logo_media_id uuid references media(id) on delete set null,
  logo_url text,   -- denormalized cache of media.public_url, avoids a join on every public read
  description text check (description is null or char_length(description) <= 2000),

  website_url text check (website_url is null or website_url ~ '^https?://'),
  affiliate_url text not null check (affiliate_url ~ '^https?://'),
  apk_url text check (apk_url is null or apk_url ~ '^https?://'),
  google_play_url text check (google_play_url is null or google_play_url ~ '^https?://'),
  app_store_url text check (app_store_url is null or app_store_url ~ '^https?://'),
  deep_link text check (deep_link is null or deep_link ~ '^[a-zA-Z][a-zA-Z0-9+.-]*://'),

  bonus_description text check (bonus_description is null or char_length(bonus_description) <= 1000),
  countries text[],           -- ISO 3166-1 alpha-2 codes; null/empty = all countries
  languages text[],           -- e.g. {uz,ru,en}; null/empty = all languages
  rating numeric(2,1) check (rating is null or (rating >= 0 and rating <= 5)),
  priority int not null default 0,   -- lower = shown first
  is_active boolean not null default true,
  is_featured boolean not null default false,

  -- Link Health (populated by /api/admin/affiliates/check-links and the
  -- scheduled /api/cron/check-affiliate-links job — see AFFILIATE_MANAGER.md)
  link_health jsonb not null default '{}'::jsonb,
  link_health_checked_at timestamptz,

  click_count bigint not null default 0,   -- fast denormalized counter; affiliate_clicks is the source of truth

  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz
);
create index idx_affiliate_partners_active on affiliate_partners(priority) where deleted_at is null and is_active = true;
create index idx_affiliate_partners_slug on affiliate_partners(slug) where deleted_at is null;
create index idx_affiliate_partners_featured on affiliate_partners(is_featured) where deleted_at is null and is_active = true;

create trigger trg_affiliate_partners_updated_at before update on affiliate_partners
  for each row execute function public.set_updated_at();
create trigger trg_audit_affiliate_partners
  after insert or update or delete on affiliate_partners
  for each row execute function public.audit_trigger();

alter table affiliate_partners enable row level security;
create policy "public read active partners" on affiliate_partners
  for select using (is_active = true and deleted_at is null);
create policy "promotions.manage full access partners" on affiliate_partners
  for all using (has_permission('promotions.manage')) with check (has_permission('promotions.manage'));

-- ---------------------------------------------------------------
-- PROMO CODES (a partner can have many)
-- ---------------------------------------------------------------
create table promo_codes (
  id uuid primary key default gen_random_uuid(),
  partner_id uuid not null references affiliate_partners(id) on delete cascade,
  code text not null check (char_length(code) between 1 and 50),
  bonus_description text check (bonus_description is null or char_length(bonus_description) <= 500),
  is_featured boolean not null default false,
  is_active boolean not null default true,
  expires_at timestamptz,
  usage_count bigint not null default 0,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz,
  unique (partner_id, code)
);
create index idx_promo_codes_partner on promo_codes(partner_id) where deleted_at is null;
create index idx_promo_codes_active on promo_codes(is_active) where deleted_at is null;

create trigger trg_promo_codes_updated_at before update on promo_codes
  for each row execute function public.set_updated_at();
create trigger trg_audit_promo_codes
  after insert or update or delete on promo_codes
  for each row execute function public.audit_trigger();

alter table promo_codes enable row level security;
create policy "public read active promo_codes" on promo_codes
  for select using (
    is_active = true and deleted_at is null and (expires_at is null or expires_at >= now())
  );
create policy "promotions.manage full access promo_codes" on promo_codes
  for all using (has_permission('promotions.manage')) with check (has_permission('promotions.manage'));

-- ---------------------------------------------------------------
-- SMART REDIRECT RULES (per-partner overrides by country/language/device)
-- Not publicly readable — only the server-side /go/{slug} route (via the
-- service-role client) and admins can see targeting logic.
-- ---------------------------------------------------------------
create table partner_redirect_rules (
  id uuid primary key default gen_random_uuid(),
  partner_id uuid not null references affiliate_partners(id) on delete cascade,
  match_type text not null check (match_type in ('country', 'language', 'device')),
  match_value text not null,   -- e.g. 'UZ', 'ru', 'mobile'
  target_url text not null check (target_url ~ '^https?://'),
  priority int not null default 0,   -- lower = evaluated first
  is_active boolean not null default true,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create index idx_redirect_rules_partner on partner_redirect_rules(partner_id, priority);

create trigger trg_redirect_rules_updated_at before update on partner_redirect_rules
  for each row execute function public.set_updated_at();
create trigger trg_audit_redirect_rules
  after insert or update or delete on partner_redirect_rules
  for each row execute function public.audit_trigger();

alter table partner_redirect_rules enable row level security;
create policy "promotions.manage full access redirect_rules" on partner_redirect_rules
  for all using (has_permission('promotions.manage')) with check (has_permission('promotions.manage'));
-- Intentionally no public policy — the /go route reads this via the
-- service-role client (server-only, not exposed to the browser).

-- ---------------------------------------------------------------
-- CLICK ANALYTICS (high-volume, append-only, time-series)
-- Written exclusively by /go/{slug} via the service-role client.
-- ---------------------------------------------------------------
create table affiliate_clicks (
  id uuid primary key default gen_random_uuid(),
  partner_id uuid references affiliate_partners(id) on delete set null,
  banner_id uuid references advertisements(id) on delete set null,
  target_url text not null,
  country text,
  device text check (device in ('desktop', 'mobile', 'tablet', 'unknown')),
  browser text,
  language text,
  referrer text,
  created_at timestamptz not null default now()
);
create index idx_affiliate_clicks_partner on affiliate_clicks(partner_id, created_at desc);
create index idx_affiliate_clicks_created_at_brin on affiliate_clicks using brin (created_at);
create index idx_affiliate_clicks_country on affiliate_clicks(country);
create index idx_affiliate_clicks_device on affiliate_clicks(device);

alter table affiliate_clicks enable row level security;
create policy "promotions.manage read affiliate_clicks" on affiliate_clicks
  for select using (has_permission('promotions.manage'));
-- No insert/update/delete policy for anyone — only the service-role
-- client (from /go/{slug}) writes here.

-- ---------------------------------------------------------------
-- BANNER MANAGER: extend the existing advertisements table (Phase 1)
-- rather than creating a second, overlapping "banners" table.
-- ---------------------------------------------------------------
alter table advertisements
  add column partner_id uuid references affiliate_partners(id) on delete set null,
  add column banner_size text check (banner_size in ('desktop', 'tablet', 'mobile', 'square', 'popup', 'sticky', 'hero')),
  add column target_countries text[],   -- null/empty = all countries
  add column target_languages text[],   -- null/empty = all languages
  add column width_px int,
  add column height_px int;

-- Retroactive URL validation (Phase 1 shipped these columns without a
-- format check) — added now as part of the Phase 3b security requirement
-- to validate every URL at the database level.
alter table advertisements
  add constraint chk_advertisements_target_url check (target_url is null or target_url ~ '^https?://'),
  add constraint chk_advertisements_image_url check (image_url is null or image_url ~ '^https?://');

create index idx_advertisements_partner on advertisements(partner_id);
create index idx_advertisements_banner_size on advertisements(banner_size) where deleted_at is null;

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0026_football_center.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0026 — PHASE 3c: FOOTBALL CENTER (provider-agnostic)
-- No football data provider is hardcoded anywhere in this schema or the
-- application code built on top of it — see lib/football/ for the
-- provider abstraction layer.
-- =========================================================

-- ---------------------------------------------------------------
-- New permission (this is the first genuinely NEW permission key added
-- since the initial 0002 seed — role_permissions must be backfilled
-- explicitly for existing roles rather than relying on the original
-- seed script, which only ran against permissions that existed then).
-- ---------------------------------------------------------------
insert into permissions (key, description) values
  ('football.manage', 'Manage Football Center: data provider settings, featured leagues/matches, videos');

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r, permissions p
where p.key = 'football.manage'
  and r.key in ('super_admin', 'admin', 'content_manager');

-- ---------------------------------------------------------------
-- Provider config lives in site_settings (non-secret: which provider is
-- active, default league/season) — the actual API keys live in
-- api_credentials (Phase 3a's secure, never-publicly-readable table).
-- ---------------------------------------------------------------
insert into site_settings (key, value) values
  ('football_provider', '{"active": null, "default_league_id": "", "default_season": ""}')
on conflict (key) do nothing;

-- ---------------------------------------------------------------
-- FOOTBALL CACHE — generic response cache for whichever provider is
-- active. Lets the Football Center survive a provider outage or rate
-- limit by serving the last-known-good response instead of crashing,
-- and reduces API usage. Server-only (no public RLS policy) — read and
-- written exclusively by lib/football/cache.ts via the service-role client.
-- ---------------------------------------------------------------
create table football_cache (
  id uuid primary key default gen_random_uuid(),
  cache_key text not null unique,   -- e.g. "fixtures:live", "standings:39:2026"
  provider text not null,
  data jsonb not null,
  cached_at timestamptz not null default now(),
  expires_at timestamptz not null
);
create index idx_football_cache_key on football_cache(cache_key);
create index idx_football_cache_expires on football_cache(expires_at);

alter table football_cache enable row level security;
-- Intentionally no policies — server-only via service-role client.

-- ---------------------------------------------------------------
-- FEATURED LEAGUES — lets the admin curate which leagues appear in the
-- Football Center (League Tables selector, homepage) without any league
-- ID ever being hardcoded in application code.
-- ---------------------------------------------------------------
create table featured_leagues (
  id uuid primary key default gen_random_uuid(),
  provider text not null,
  external_league_id text not null,
  name text not null,
  logo_url text,
  country text,
  season text,
  position int not null default 0,
  is_active boolean not null default true,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (provider, external_league_id)
);
create index idx_featured_leagues_active on featured_leagues(position) where is_active = true;

create trigger trg_featured_leagues_updated_at before update on featured_leagues
  for each row execute function public.set_updated_at();
create trigger trg_audit_featured_leagues
  after insert or update or delete on featured_leagues
  for each row execute function public.audit_trigger();

alter table featured_leagues enable row level security;
create policy "public read active featured_leagues" on featured_leagues
  for select using (is_active = true);
create policy "football.manage full access featured_leagues" on featured_leagues
  for all using (has_permission('football.manage')) with check (has_permission('football.manage'));

-- ---------------------------------------------------------------
-- FEATURED FIXTURES — admin "pins" a specific match (from whichever
-- provider is active) to be highlighted; the live fixture data itself is
-- still fetched/cached from the provider at render time, only the pin +
-- an optional editorial note are stored locally.
-- ---------------------------------------------------------------
create table featured_fixtures (
  id uuid primary key default gen_random_uuid(),
  provider text not null,
  external_fixture_id text not null,
  note text,
  position int not null default 0,
  is_active boolean not null default true,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (provider, external_fixture_id)
);
create index idx_featured_fixtures_active on featured_fixtures(position) where is_active = true;

create trigger trg_featured_fixtures_updated_at before update on featured_fixtures
  for each row execute function public.set_updated_at();
create trigger trg_audit_featured_fixtures
  after insert or update or delete on featured_fixtures
  for each row execute function public.audit_trigger();

alter table featured_fixtures enable row level security;
create policy "public read active featured_fixtures" on featured_fixtures
  for select using (is_active = true);
create policy "football.manage full access featured_fixtures" on featured_fixtures
  for all using (has_permission('football.manage')) with check (has_permission('football.manage'));

-- ---------------------------------------------------------------
-- FOOTBALL VIDEOS — editorial content, not from any provider API.
-- ---------------------------------------------------------------
create table football_videos (
  id uuid primary key default gen_random_uuid(),
  title text not null check (char_length(title) between 1 and 200),
  video_url text not null check (video_url ~ '^https?://'),
  thumbnail_media_id uuid references media(id) on delete set null,
  description text,
  is_featured boolean not null default false,
  is_active boolean not null default true,
  published_at timestamptz not null default now(),
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz
);
create index idx_football_videos_active on football_videos(published_at desc) where is_active = true and deleted_at is null;

create trigger trg_football_videos_updated_at before update on football_videos
  for each row execute function public.set_updated_at();
create trigger trg_audit_football_videos
  after insert or update or delete on football_videos
  for each row execute function public.audit_trigger();

alter table football_videos enable row level security;
create policy "public read active football_videos" on football_videos
  for select using (is_active = true and deleted_at is null);
create policy "football.manage full access football_videos" on football_videos
  for all using (has_permission('football.manage')) with check (has_permission('football.manage'));

