-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0028_media_library_and_push.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0028 — PHASE 4: MEDIA LIBRARY (gallery UI backing) + PUSH NOTIFICATIONS
-- =========================================================

-- media table already exists (Phase 1) with everything the gallery UI
-- needs (file_name, public_url, mime_type, file_size_bytes, uploaded_by,
-- created_at, deleted_at) — no schema change needed there, only a proper
-- browsing/search UI (this phase's app-layer work).

-- ---------------------------------------------------------------
-- PUSH SUBSCRIPTIONS (Web Push)
-- Visitors opt in from the browser; no login required, so there is no
-- "owner" to scope RLS to. The endpoint URL itself is a long, unguessable,
-- unique value issued by the browser's push service — it functions like a
-- bearer token, which is why public insert/delete-by-endpoint is safe.
-- ---------------------------------------------------------------
create table push_subscriptions (
  id uuid primary key default gen_random_uuid(),
  endpoint text not null unique,
  p256dh text not null,
  auth text not null,
  user_agent text,
  country text,
  created_at timestamptz not null default now(),
  last_used_at timestamptz
);
create index idx_push_subscriptions_created_at on push_subscriptions(created_at desc);

alter table push_subscriptions enable row level security;

-- Any visitor can subscribe (opt-in) or unsubscribe (by their own,
-- unguessable endpoint) — this is the standard Web Push trust model.
create policy "public insert subscription" on push_subscriptions
  for insert with check (true);
create policy "public delete own subscription" on push_subscriptions
  for delete using (true);

-- Only admins with settings.manage may LIST subscriptions (e.g. to show
-- a subscriber count in the admin UI) — the raw endpoint/keys are still
-- sensitive (they allow sending push messages to that specific browser).
create policy "settings.manage read subscriptions" on push_subscriptions
  for select using (has_permission('settings.manage'));

-- ---------------------------------------------------------------
-- PUSH NOTIFICATION LOG (audit trail of what was broadcast, and to how
-- many recipients / how many failed) — distinct from the generic
-- audit_logs table because this tracks a bulk external side-effect, not
-- a single row change.
-- ---------------------------------------------------------------
create table push_notification_log (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  body text not null,
  url text,
  sent_by uuid references profiles(id) on delete set null,
  recipients_count int not null default 0,
  failures_count int not null default 0,
  created_at timestamptz not null default now()
);

alter table push_notification_log enable row level security;
create policy "settings.manage full access push_log" on push_notification_log
  for all using (has_permission('settings.manage')) with check (has_permission('settings.manage'));

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0029_final_release_hardening.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0029 — FINAL RELEASE: audit fixes
-- Found during the Final Release full-project audit. Applied as a new
-- migration rather than editing migration history, per established
-- practice (see 0020's own header for the same rationale).
-- =========================================================

-- ---------------------------------------------------------------
-- FIX 1 — redundant index. `cache_key` already has a UNIQUE constraint
-- (0026), which Postgres backs with its own implicit unique btree index.
-- The separate `idx_football_cache_key` index duplicated it exactly —
-- same column, same order — adding write overhead for zero query benefit.
-- ---------------------------------------------------------------
drop index if exists idx_football_cache_key;

-- Note: login_attempts(ip_address, created_at) was checked during this
-- audit and already has the correct composite index from migration 0022
-- — no fix needed there.

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0030_live_streaming.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0030 — VERSION 1.1.0: LIVE STREAMING SYSTEM
-- No streaming provider is hardcoded. Providers are entirely
-- admin-defined data (name, base API URL, credentials) consumed by ONE
-- generic, configurable adapter (lib/streaming/) — see
-- LIVE_STREAMING_ARCHITECTURE.md for why this differs from the Football
-- Data provider design (Phase 3c had 3 REAL, documented APIs to adapt to;
-- no such public "official sports streaming API" exists to model against,
-- so the architecture stays provider-shape-agnostic by design).
-- =========================================================

-- ---------------------------------------------------------------
-- New permission (backfilled to existing roles — see 0026 for why this
-- backfill pattern is necessary rather than relying on the original seed).
-- ---------------------------------------------------------------
insert into permissions (key, description) values
  ('streaming.manage', 'Manage live streaming providers and match stream assignments');

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r, permissions p
where p.key = 'streaming.manage'
  and r.key in ('super_admin', 'admin', 'content_manager');

-- ---------------------------------------------------------------
-- STREAMING PROVIDERS
-- Credentials (api_credentials.key = 'streaming:{provider.id}:api_key' /
-- '...:api_secret') are stored ENCRYPTED (lib/security/encryption.ts,
-- AES-256-GCM) — this table itself never holds the key/secret value,
-- only connection status/metadata.
-- ---------------------------------------------------------------
create table streaming_providers (
  id uuid primary key default gen_random_uuid(),
  key text not null unique,     -- slug, e.g. 'provider-a' — used to build the credential keys
  name text not null check (char_length(name) between 1 and 100),
  base_api_url text not null check (base_api_url ~ '^https?://'),
  priority int not null default 0,
  is_active boolean not null default true,
  connection_status text not null default 'unknown' check (connection_status in ('unknown', 'connected', 'error')),
  last_sync_at timestamptz,
  last_error text,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz
);
create index idx_streaming_providers_active on streaming_providers(priority) where is_active = true and deleted_at is null;

create trigger trg_streaming_providers_updated_at before update on streaming_providers
  for each row execute function public.set_updated_at();
create trigger trg_audit_streaming_providers
  after insert or update or delete on streaming_providers
  for each row execute function public.audit_trigger();

alter table streaming_providers enable row level security;
create policy "streaming.manage full access providers" on streaming_providers
  for all using (has_permission('streaming.manage')) with check (has_permission('streaming.manage'));
-- Intentionally NO public policy — base_api_url and connection metadata
-- are not needed by the public site directly. The public site learns
-- only "is a stream available + provider display name" via the
-- /api/streaming/* routes (service-role, selecting only safe columns).

-- ---------------------------------------------------------------
-- MATCH STREAMS
-- Assigns one or more streaming providers to a specific match. The match
-- itself is identified by (football_provider, external_fixture_id) —
-- i.e. whichever Football Data provider (Phase 3c) the fixture ID
-- belongs to — exactly like featured_fixtures (Phase 3c) already does,
-- for the same reason: fixture IDs are only unique within their own
-- provider's ID space.
-- ---------------------------------------------------------------
create table match_streams (
  id uuid primary key default gen_random_uuid(),
  football_provider text not null,
  external_fixture_id text not null,
  streaming_provider_id uuid not null references streaming_providers(id) on delete cascade,
  external_stream_id text,   -- the streaming provider's own identifier for this stream, if different from the fixture id
  is_primary boolean not null default false,
  is_active boolean not null default true,
  starts_at timestamptz,
  ends_at timestamptz,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (football_provider, external_fixture_id, streaming_provider_id)
);
create index idx_match_streams_fixture on match_streams(football_provider, external_fixture_id) where is_active = true;
create index idx_match_streams_provider on match_streams(streaming_provider_id);

create trigger trg_match_streams_updated_at before update on match_streams
  for each row execute function public.set_updated_at();
create trigger trg_audit_match_streams
  after insert or update or delete on match_streams
  for each row execute function public.audit_trigger();

alter table match_streams enable row level security;
create policy "streaming.manage full access match_streams" on match_streams
  for all using (has_permission('streaming.manage')) with check (has_permission('streaming.manage'));
-- No public policy — the public site reaches this only through
-- /api/streaming/* (service-role), which returns availability + provider
-- name only, never raw rows.

-- ---------------------------------------------------------------
-- STREAMING CONNECTION LOGS (Test Connection results + sync history —
-- the "Error Logs" admin panel requirement).
-- ---------------------------------------------------------------
create table streaming_connection_logs (
  id uuid primary key default gen_random_uuid(),
  provider_id uuid references streaming_providers(id) on delete cascade,
  event_type text not null check (event_type in ('test_connection', 'sync')),
  success boolean not null,
  message text,
  created_at timestamptz not null default now()
);
create index idx_streaming_connection_logs_provider on streaming_connection_logs(provider_id, created_at desc);

alter table streaming_connection_logs enable row level security;
create policy "streaming.manage read connection_logs" on streaming_connection_logs
  for select using (has_permission('streaming.manage'));
-- No insert/update/delete policy for anyone — only the server-side test
-- connection / sync routes (service-role) write here.

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0031_donation_system.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0031 — VERSION 1.2.0: DONATION & SUPPORT SYSTEM
-- Gateway credentials use the same encryption module as Live Streaming
-- (v1.1.0, lib/security/encryption.ts) — no separate security system
-- built for this feature. Crypto wallet addresses are NOT secret (donors
-- must see them to send funds), so they live in plain columns here.
-- =========================================================

insert into permissions (key, description) values
  ('donations.manage', 'Manage payment methods, view donations, export reports');

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r, permissions p
where p.key = 'donations.manage'
  and r.key in ('super_admin', 'admin', 'content_manager');

-- ---------------------------------------------------------------
-- PAYMENT METHODS
-- One table for both payment gateways (Stripe/PayPal/future) and crypto
-- wallets (USDT/BTC/ETH/SOL/future) via `method_type`. Gateway API
-- credentials are NEVER stored here — they live encrypted in
-- api_credentials (keyed 'donation:{payment_method.id}:api_key' etc,
-- same pattern as Live Streaming). Crypto wallet_address is public
-- information by nature (donors must see it), so it's a plain column.
-- ---------------------------------------------------------------
create table payment_methods (
  id uuid primary key default gen_random_uuid(),
  key text not null unique,
  name text not null check (char_length(name) between 1 and 100),
  method_type text not null check (method_type in ('gateway', 'crypto')),

  -- gateway-only fields
  provider_key text check (provider_key in ('stripe', 'paypal', 'generic')),
  base_api_url text,       -- only used when provider_key = 'generic' (Stripe/PayPal have fixed, well-known API hosts)

  -- crypto-only fields
  crypto_symbol text,      -- e.g. 'USDT', 'BTC', 'ETH', 'SOL'
  network text,            -- e.g. 'TRC20', 'ERC20', 'Mainnet'
  wallet_address text,

  display_order int not null default 0,
  is_active boolean not null default true,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  deleted_at timestamptz,

  constraint chk_payment_method_shape check (
    (method_type = 'gateway' and provider_key is not null and wallet_address is null)
    or
    (method_type = 'crypto' and wallet_address is not null and provider_key is null)
  )
);
create index idx_payment_methods_active on payment_methods(display_order) where is_active = true and deleted_at is null;

create trigger trg_payment_methods_updated_at before update on payment_methods
  for each row execute function public.set_updated_at();
create trigger trg_audit_payment_methods
  after insert or update or delete on payment_methods
  for each row execute function public.audit_trigger();

alter table payment_methods enable row level security;
-- Public read is safe: no secrets live in this table (gateway keys are
-- elsewhere; wallet addresses are meant to be public).
create policy "public read active payment_methods" on payment_methods
  for select using (is_active = true and deleted_at is null);
create policy "donations.manage full access payment_methods" on payment_methods
  for all using (has_permission('donations.manage')) with check (has_permission('donations.manage'));

-- ---------------------------------------------------------------
-- DONATIONS
-- Fully server-mediated: no public RLS policy at all (not even insert).
-- All creation goes through /api/donations/* route handlers (service-role)
-- so amount limits, message length, and provider dispatch are enforced
-- in exactly one place — see DONATION_SYSTEM.md.
-- ---------------------------------------------------------------
create table donations (
  id uuid primary key default gen_random_uuid(),
  payment_method_id uuid references payment_methods(id) on delete set null,
  amount numeric(12, 2) not null check (amount > 0 and amount <= 1000000),
  currency text not null default 'USD' check (currency in ('USD', 'EUR', 'UZS')),
  donor_name text check (donor_name is null or char_length(donor_name) <= 80),
  donor_email text,
  message text check (message is null or char_length(message) <= 500),
  is_anonymous boolean not null default false,
  is_public boolean not null default true,
  status text not null default 'pending' check (status in ('pending', 'completed', 'failed', 'refunded')),
  external_transaction_id text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create index idx_donations_status on donations(status);
create index idx_donations_public_completed on donations(created_at desc) where status = 'completed' and is_public = true and is_anonymous = false;
create index idx_donations_created_at_brin on donations using brin (created_at);

create trigger trg_donations_updated_at before update on donations
  for each row execute function public.set_updated_at();
create trigger trg_audit_donations
  after insert or update or delete on donations
  for each row execute function public.audit_trigger();

alter table donations enable row level security;
create policy "donations.manage full access donations" on donations
  for all using (has_permission('donations.manage')) with check (has_permission('donations.manage'));
-- No public policy whatsoever — see header note.

-- ---------------------------------------------------------------
-- DONATION WEBHOOK LOG (webhook verification audit trail — every
-- inbound webhook, verified or not, is recorded so a rejected/forged
-- attempt is visible to admins, not silently dropped).
-- ---------------------------------------------------------------
create table donation_webhook_log (
  id uuid primary key default gen_random_uuid(),
  payment_method_id uuid references payment_methods(id) on delete set null,
  verified boolean not null,
  event_type text,
  donation_id uuid references donations(id) on delete set null,
  raw_payload jsonb,
  created_at timestamptz not null default now()
);
create index idx_donation_webhook_log_method on donation_webhook_log(payment_method_id, created_at desc);

alter table donation_webhook_log enable row level security;
create policy "donations.manage read webhook_log" on donation_webhook_log
  for select using (has_permission('donations.manage'));
-- No insert/update/delete policy for anyone — only the webhook route
-- (service-role) writes here.

-- ///////////////////////////////////////////////////////////
-- FILE: migrations/0032_v1_3_0_hardening.sql
-- ///////////////////////////////////////////////////////////
-- =========================================================
-- 0032 — VERSION 1.3.0: PRODUCTION INTEGRATION & VERIFICATION
-- Found during full-system rate-limiting review: several genuinely
-- public write endpoints (view-count tracking, promo-code usage
-- tracking, push subscribe/unsubscribe) had no abuse protection at all.
-- Low severity (cosmetic metrics / opt-in noise, not financial or data
-- risk), but still real gaps — see PRODUCTION_READINESS_REPORT.md.
-- =========================================================

-- Generic, reusable rate-limit ledger — server-only (no RLS policies),
-- written exclusively via lib/security/rateLimit.ts. A single shared
-- table instead of a bespoke one per feature (login/streaming/donations
-- already had their own domain-table-based counters before this
-- version and are intentionally left as-is to avoid touching
-- already-verified code — see PRODUCTION_READINESS_REPORT.md).
create table rate_limit_events (
  id uuid primary key default gen_random_uuid(),
  bucket text not null,
  created_at timestamptz not null default now()
);
create index idx_rate_limit_events_bucket on rate_limit_events(bucket, created_at desc);
-- Old entries are cheap to accumulate (small rows, short lookback
-- windows) but a scheduled cleanup is straightforward to add later via
-- the existing Vercel Cron (vercel.json) if the table grows large.

alter table rate_limit_events enable row level security;
-- Intentionally no policies — server-only via service-role client.

